import { Component, h, Prop, Element } from '@stencil/core';

@Component({
  tag: 'disclaimer-component',
  styleUrl: 'disclaimer.css',
  shadow: true,
})
export class Disclaimer {
  @Element() el: HTMLElement;
  @Prop() content: HTMLElement;
  @Prop() optionalClass: string = '';

  componentDidLoad() {
    this.ensureLinksAreFocusable();
  }

  componentDidUpdate() {
    this.ensureLinksAreFocusable();
  }

  private ensureLinksAreFocusable() {
    if (!this.el.shadowRoot) return;
    
    const links = this.el.shadowRoot.querySelectorAll('a');
    links.forEach((link: HTMLAnchorElement) => {
      // Ensure link is in tab order
      if (!link.hasAttribute('tabindex')) {
        link.setAttribute('tabindex', '0');
      }
      
      // Ensure keyboard interaction works
      if (!link.hasAttribute('data-keyboard-enabled')) {
        link.addEventListener('keydown', (e: KeyboardEvent) => {
          if (e.key === 'Enter' || e.key === ' ') {
            e.preventDefault();
            link.click();
          }
        });
        link.setAttribute('data-keyboard-enabled', 'true');
      }
    });
  }

  render() {
    if (!this.content) {
      return null;
    }

    return (
      <div 
        class={`disclaimer-container ${this.optionalClass}`}
        role="note" 
        aria-label="Disclaimer"
        innerHTML={this.content.innerHTML}
      ></div>
    );
  }
}